const config = $('Config').first().json;
const allTickers = $('Binance 24h Ticker (All)').first().json;

if (!Array.isArray(allTickers)) {
  throw new Error('Binance API returned non-array (likely rate-limited or down)');
}

// Filter to clean spot USDT pairs (exclude leveraged tokens)
const excludeSuffixes = ['UPUSDT', 'DOWNUSDT', 'BEARUSDT', 'BULLUSDT'];
const usdtPairs = allTickers.filter(t =>
  t.symbol.endsWith('USDT') &&
  !excludeSuffixes.some(suf => t.symbol.endsWith(suf))
);

// Tradeable = has minimum 24h volume
const minVol = config.minVolume24hUsd || 10000000;
const tradeable = usdtPairs.filter(t => parseFloat(t.quoteVolume) > minVol);

const topN = config.topMoverCount || 5;
const sortedGainers = [...tradeable].sort((a, b) => parseFloat(b.priceChangePercent) - parseFloat(a.priceChangePercent));
const sortedLosers  = [...tradeable].sort((a, b) => parseFloat(a.priceChangePercent) - parseFloat(b.priceChangePercent));

// Watchlist (always include even if low volume)
const watchSymbols = (config.watchlist || 'BTCUSDT,ETHUSDT').split(',').map(s => s.trim().toUpperCase());
const tickerMap = Object.fromEntries(allTickers.map(t => [t.symbol, t]));
const watchData = watchSymbols.map(sym => tickerMap[sym]).filter(Boolean);

const fmt = (t) => ({
  symbol: t.symbol.replace(/USDT$/, ''),
  price: parseFloat(t.lastPrice),
  change24hPct: Number(parseFloat(t.priceChangePercent).toFixed(2)),
  volume24hUsd: Math.round(parseFloat(t.quoteVolume)),
  high24h: parseFloat(t.highPrice),
  low24h: parseFloat(t.lowPrice),
});

const payload = {
  timestamp: new Date().toISOString(),
  timestampLocal: new Date().toLocaleString(config.language === 'tr' ? 'tr-TR' : 'en-US', { timeZone: 'Europe/Istanbul' }),
  topGainers: sortedGainers.slice(0, topN).map(fmt),
  topLosers:  sortedLosers.slice(0, topN).map(fmt),
  watchlist:  watchData.map(fmt),
};

// Build LLM prompt
const isTurkish = config.language === 'tr';
const systemPrompt = isTurkish
  ? 'Sen profesyonel bir kripto piyasası analistisin. Verilen anlık piyasa verisinden, kısa ve aksiyona yönelik sinyaller üret. Türkçe akıcı yaz. Çıktın YALNIZCA JSON olmalı, hiçbir açıklama veya markdown kullanma.'
  : 'You are a professional crypto market analyst. From the live data, produce concise actionable signals. Output ONLY valid JSON — no markdown or commentary.';

const userPrompt = (isTurkish
  ? `Anlık kripto piyasa verisi (Binance USDT spot):\n${JSON.stringify(payload, null, 2)}\n\nAşağıdaki şemada JSON üret:\n{\n  "marketSentiment": "BULLISH|BEARISH|NEUTRAL",\n  "sentimentReasoning": "1 cümle",\n  "signals": [\n    {\n      "symbol": "BTC",\n      "direction": "LONG|SHORT|HOLD",\n      "entry": 67000,\n      "stopLoss": 65000,\n      "takeProfit": 70000,\n      "confidence": 0.7,\n      "reasoning": "1-2 cümle Türkçe"\n    }\n  ],\n  "topPick": "En iyi fırsat ve kısa neden"\n}\n\nKurallar: Watchlist'teki HER coin + top 3 gainer için bir signal üret. Confidence 0-1 arası. Entry ÖNERİSİ olarak güncel fiyata yakın bir seviye (limit order için). StopLoss kayıp kabul edilebilecek seviye, TakeProfit makul hedef. Direction HOLD ise SL/TP için 0 yaz.`
  : `Current crypto market data (Binance USDT spot):\n${JSON.stringify(payload, null, 2)}\n\nGenerate JSON with this shape:\n{\n  "marketSentiment": "BULLISH|BEARISH|NEUTRAL",\n  "sentimentReasoning": "1 sentence",\n  "signals": [\n    {\n      "symbol": "BTC",\n      "direction": "LONG|SHORT|HOLD",\n      "entry": 67000,\n      "stopLoss": 65000,\n      "takeProfit": 70000,\n      "confidence": 0.7,\n      "reasoning": "1-2 concise sentences"\n    }\n  ],\n  "topPick": "Best opportunity + brief why"\n}\n\nRules: Generate a signal for EVERY watchlist coin + top 3 gainers. Confidence 0-1. Entry should be a realistic limit order level near current price. StopLoss = acceptable loss point. TakeProfit = realistic target. If HOLD, use 0 for SL/TP.`);

return [{ json: { ...payload, systemPrompt, userPrompt, language: config.language } }];

const resp = $input.first().json;
const raw = resp?.choices?.[0]?.message?.content ?? '';
const lang = $('Analyze Market & Build Prompt').first().json.language || 'tr';
const isTr = lang === 'tr';

// Strip code fences if Grok wrapped output
const cleaned = raw.replace(/^```json\s*/i, '').replace(/\s*```\s*$/i, '').trim();

let signal;
try { signal = JSON.parse(cleaned); }
catch (e) {
  const fallback = isTr
    ? `⚠️ <b>Sinyal Üretilemedi</b>\n\nGrok yanıtı JSON olarak parse edilemedi:\n<pre>${cleaned.slice(0, 400)}</pre>`
    : `⚠️ <b>Signal Generation Failed</b>\n\nGrok response not valid JSON:\n<pre>${cleaned.slice(0, 400)}</pre>`;
  return [{ json: { text: fallback, parse_mode: 'HTML' } }];
}

const dirEmoji = { LONG: '🟢', SHORT: '🔴', HOLD: '⚪' };
const sentEmoji = { BULLISH: '📈', BEARISH: '📉', NEUTRAL: '➡️' };

const headerWord = isTr ? 'Kripto Sinyalleri' : 'Crypto Signals';
const confWord = isTr ? 'Güven' : 'Confidence';
const topPickWord = isTr ? 'Öne Çıkan' : 'Top Pick';
const disclaimer = isTr
  ? '<i>Bu bir yatırım tavsiyesi değildir. Veri: Binance + xAI Grok.</i>'
  : '<i>Not financial advice. Data: Binance + xAI Grok.</i>';

const fmtPrice = (n) => {
  if (n === 0) return '—';
  if (n >= 1000) return n.toLocaleString('en-US', { maximumFractionDigits: 2 });
  if (n >= 1)    return n.toFixed(2);
  if (n >= 0.01) return n.toFixed(4);
  return n.toFixed(8);
};

const lines = [];
const ts = $('Analyze Market & Build Prompt').first().json.timestampLocal;
lines.push(`<b>${headerWord}</b>  ${sentEmoji[signal.marketSentiment] || ''} <b>${signal.marketSentiment ?? '?'}</b>`);
lines.push(`<i>${ts}</i>`);
if (signal.sentimentReasoning) lines.push(`<i>${signal.sentimentReasoning}</i>`);
lines.push('');

for (const s of signal.signals ?? []) {
  const e = dirEmoji[s.direction] || '•';
  lines.push(`${e} <b>${s.symbol}</b> — ${s.direction}`);
  if (s.direction !== 'HOLD' && s.entry) {
    lines.push(`   Entry <code>${fmtPrice(s.entry)}</code>  •  SL <code>${fmtPrice(s.stopLoss)}</code>  •  TP <code>${fmtPrice(s.takeProfit)}</code>`);
  }
  if (typeof s.confidence === 'number') {
    lines.push(`   ${confWord}: <b>${Math.round(s.confidence * 100)}%</b>`);
  }
  if (s.reasoning) lines.push(`   <i>${s.reasoning}</i>`);
  lines.push('');
}

if (signal.topPick) {
  lines.push(`🎯 <b>${topPickWord}:</b> ${signal.topPick}`);
  lines.push('');
}
lines.push(disclaimer);

const text = lines.join('\n').slice(0, 4000); // Telegram limit

return [{ json: { text, parse_mode: 'HTML', signal } }];
